import{_ as t,o as a,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse(`{"title":"23. Overtime And Penalty Rates","description":"","frontmatter":{"title":"23. Overtime And Penalty Rates","eba":"Children's Services Award 2010","topics":["leave","public-holidays","hours","overtime","penalty-rates","shift-work","rosters","allowances","classifications","employment","termination","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/hours-of-work/23-overtime-and-penalty-rates.md","filePath":"ebas/childrens-services/hours-of-work/23-overtime-and-penalty-rates.md"}`),n={name:"ebas/childrens-services/hours-of-work/23-overtime-and-penalty-rates.md"};function i(s,e,l,p,h,m){return a(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="_23-overtime-and-penalty-rates" tabindex="-1">23. Overtime And Penalty Rates <a class="header-anchor" href="#_23-overtime-and-penalty-rates" aria-label="Permalink to &quot;23. Overtime And Penalty Rates&quot;">​</a></h1><ol><li><p>Entitlement to overtime rates</p><p>a. A full-time employee is paid at overtime rates for any work performed outside of their ordinary hours of work.</p><p>b. A part-time employee is paid at overtime rates in the circumstances specified in <a href="/eba/ebas/childrens-services/employment/10-types-of-employment.html">clause 10</a>.4(f).</p><p>c. A casual employee is paid at overtime rates in the circumstances specified in <a href="/eba/ebas/childrens-services/employment/10-types-of-employment.html">clause 10</a>.5(e).</p></li><li><p>Overtime rates</p></li></ol><p>[23.2(a) substituted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR723880.htm" target="_blank" rel="noreferrer">PR723880</a> ppc 20Nov20]</p><p>a. Full-time and part-time employees will be paid overtime at the rate of 150% of the hourly rate (plus any all-purpose allowance payable) for the first 2 hours and 200% of the hourly rate (plus any all-purpose allowance payable) after 2 hours. In calculating overtime, each day&#39;s work will stand alone.</p><p>b. Casual employees will be paid overtime at the rate of <strong>175%</strong> of the hourly rate (plus any all-purpose allowance payable) for the first 2 hours and <strong>225%</strong> of the hourly rate (plus any all-purpose allowance payable) after 2 hours. In calculating overtime, each day&#39;s work will stand alone.</p><p>NOTE: The overtime rates for casual employees have been calculated by adding the casual loading prescribed by <a href="/eba/ebas/childrens-services/employment/10-types-of-employment.html">clause 10</a>.5(a) to the overtime rates for full-time and part-time employees prescribed by clause 23.2(a).</p><p>[23.2(b) renumbered as 23.2(c) by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR723880.htm" target="_blank" rel="noreferrer">PR723880</a> ppc 20Nov20]</p><p>c. Where, due to a genuine and pressing emergency situation, an employee is required to remain at work after their normal finishing time such time will be paid at the ordinary rate for the employee&#39;s classification. Provided that such emergency overtime does not exceed one hour per week. For the purposes of this subclause an <strong>emergency situation</strong> may include a natural disaster affecting a parent, another employee or the centre/service, the death of a child or parent, or a child requiring urgent hospitalisation or medical attention.</p><p>[23.2(c) deleted by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR584086.htm" target="_blank" rel="noreferrer">PR584086</a> ppc 22Aug16]</p><ol><li>Time off instead of payment for overtime</li></ol><p>a. An employee and employer may agree in writing to the employee taking time off instead of being paid for a particular amount of overtime that has been worked by the employee.</p><p>b. Any amount of overtime that has been worked by an employee in a particular pay period and that is to be taken as time off instead of the employee being paid for it must be the subject of a separate agreement under clause 23.3.</p><p>c. An agreement must state each of the following:</p><pre><code>i.  the number of overtime hours to which it applies and when those
    hours were worked;

ii. that the employer and employee agree that the employee may take
    time off instead of being paid for the overtime;

iii. that, if the employee requests at any time, the employer must
     pay the employee, for overtime covered by the agreement but not
     taken as time off, at the overtime rate applicable to the
     overtime when worked;

iv. that any payment mentioned in subparagraph (iii) must be made in
    the next pay period following the request.
</code></pre><p>Note: An example of the type of agreement required by this clause is set out at <a href="/eba/ebas/childrens-services/schedules/h-agreement-for-time-off-instead-of-payment-for-overtime.html">Schedule H</a>. There is no requirement to use the form of agreement set out at <a href="/eba/ebas/childrens-services/schedules/h-agreement-for-time-off-instead-of-payment-for-overtime.html">Schedule H</a>. An agreement under clause 23.3 can also be made by an exchange of emails between the employee and employer, or by other electronic means.</p><p>d. The period of time off that an employee is entitled to take is the same as the number of overtime hours worked.</p><p>EXAMPLE: By making an agreement under clause 23.3 an employee who worked 2 overtime hours is entitled to 2 hours&#39; time off.</p><p>e. Time off must be taken:</p><pre><code>i.  within the period of 6 months after the overtime is worked; and

ii. at a time or times within that period of 6 months agreed by the
    employee and employer.
</code></pre><p>f. If the employee requests at any time, to be paid for overtime covered by an agreement under clause 23.3 but not taken as time off, the employer must pay the employee for the overtime, in the next pay period following the request, at the overtime rate applicable to the overtime when worked.</p><p>g. If time off for overtime that has been worked is not taken within the period of 6 months mentioned in paragraph (e), the employer must pay the employee for the overtime, in the next pay period following those 6 months, at the overtime rate applicable to the overtime when worked.</p><p>h. The employer must keep a copy of any agreement under clause 23.3 as an employee record.</p><p>i. An employer must not exert undue influence or undue pressure on an employee in relation to a decision by the employee to make, or not make, an agreement to take time off instead of payment for overtime.</p><p>j. An employee may, under section 65 of the Act, request to take time off, at a time or times specified in the request or to be subsequently agreed by the employer and the employee, instead of being paid for overtime worked by the employee. If the employer agrees to the request then clause 23.3 will apply, including the requirement for separate written agreements under paragraph (b) for overtime that has been worked.</p><p>Note: If an employee makes a request under section 65 of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a> for a change in working arrangements, the employer may only refuse that request on reasonable business grounds (see section 65A(3) of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>).</p><p>k. If, on the termination of the employee&#39;s employment, time off for overtime worked by the employee to which clause 23.3 applies has not been taken, the employer must pay the employee for the overtime at the overtime rate applicable to the overtime when worked.</p><p>Note: Under section 345(1) of the Act, a person must not knowingly or recklessly make a false or misleading representation about the workplace rights of another person under clause 23.3.</p><ol><li>Shiftwork</li></ol><p>a. Despite the provisions of <a href="/eba/ebas/childrens-services/hours-of-work/21-ordinary-hours-of-work-and-rostering.html">clauses 21</a>.1, 21.2 and 21.3, employees may be employed as shiftworkers.</p><p>b. The ordinary hours inclusive of meal breaks for shiftworkers will not, without payment of overtime, exceed an average of 38 hours per week to be worked over a one, two or four week cycle.</p><p>c. The following allowances will be paid for shiftwork:</p><p><strong>Shift</strong> <strong>% loading</strong></p><hr><p>Early morning 10 Afternoon 15 Night shift, rotating with day or afternoon 17.5 Night shift, non-rotating 30</p><p>d. Definitions</p><pre><code>i.  **Early morning shift** means any shift commencing at or after
    5.00 am and before 6.00 am.

ii. **Afternoon shift** means any shift finishing after 6.30 pm and
    at or before midnight.

iii. **Night shift** means any shift finishing after midnight and at
     or before 8.00 am or any shift commencing at or before midnight
     and finishing before 5.00 am.

iv. **Night shift, non-rotating** means any night shift system in
    which night shifts do not rotate or alternate with another shift
    so as to give the employee at least one third of their working
    time off night shift in each roster cycle.
</code></pre><ol><li>Weekend and public holiday work</li></ol><p>a. Overtime on a Saturday will be paid at the rate of time and a half for the first two hours and double time thereafter.</p><p>b. Provided that shiftworkers required to work ordinary hours on a Saturday will be paid at the rate of time and a half for all hours worked. Overtime worked on a Saturday by shiftworkers will be paid at time and a half for the first two hours and double time thereafter.</p><p>c. All time worked on a Sunday will be paid at the rate of double time.</p><p>[23.5(d) substituted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr747480.htm" target="_blank" rel="noreferrer">PR747480</a> ppc 14Nov22]</p><p>d. All time worked on a public holiday will be paid at the rate of double time and a half. Where both a public holiday and a substitute day or part-day are worked, public holiday penalties are payable for only one of those days or part-days, at the election of the employee.</p><p>e. Employees working on a Saturday, Sunday or public holiday will receive a minimum payment of four hours pay.</p><p>[23.5(f) inserted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/pr747480.htm" target="_blank" rel="noreferrer">PR747480</a> ppc 14Nov22]</p><p>f. Hours of work performed immediately before or after a part-day public holiday, that form part of one continuous shift, are counted as part of the minimum payment/engagement period in clause 23.5(e).</p><p>Plain language terms: OT, penalty rates, weekend rates.</p>`,46)])])}const u=t(n,[["render",i]]);export{f as __pageData,u as default};
